import{_ as t,c as s,o as p,ae as r}from"./chunks/framework.Cd-3tpCq.js";const g=JSON.parse('{"title":"圈地帮助","description":"","frontmatter":{},"headers":[],"relativePath":"bz.md","filePath":"bz.md"}'),a={name:"bz.md"};function l(i,e,o,c,n,d){return p(),s("div",null,e[0]||(e[0]=[r('<h1 id="圈地帮助" tabindex="-1">圈地帮助 <a class="header-anchor" href="#圈地帮助" aria-label="Permalink to &quot;圈地帮助&quot;">​</a></h1><h2 id="总指令" tabindex="-1">总指令 <a class="header-anchor" href="#总指令" aria-label="Permalink to &quot;总指令&quot;">​</a></h2><p>/res ? —— 查看帮助</p><h2 id="领地创建与删除" tabindex="-1">领地创建与删除 <a class="header-anchor" href="#领地创建与删除" aria-label="Permalink to &quot;领地创建与删除&quot;">​</a></h2><p>/res create [领地名] —— 创建一个领地</p><p>/res remove &lt;领地名&gt; —— 删除一个领地</p><p>/res subzone [子领地名] —— 在所处的领地中创建一个子领地</p><p>/res auto [领地名] [范围] —— 自动在你站着的位置为中心，创建你能创建最大的领地</p><p>/res select [x] [y] [z] —— 选取以你为中心需要被保护的区域，（Z=高度，X/Y=横轴）</p><p>/res select size —— 显示所选区域大小</p><p>/res select cost —— 显示已选择区域价格</p><p>/res select auto [玩家] —— 打开自动选择区域</p><p>/res select expand [数值] —— 选区向面对的方向选择扩展数值大小</p><p>/res contract &lt;领地&gt; [缩小单位] —— 从你面对的方向缩小领地</p><p>/res select shift [数值] —— 选区向面对的方向平移</p><p>/res select vert —— 高度从天空扩展到基岩</p><p>/res select sky —— 高度扩展到天框</p><p>/res select bedrock —— 高度扩展都基岩</p><p>/res select chunk —— 选择目前所在区块</p><p>/res select worldedit —— 使用Worldedit的选区作为领地选区</p><p>/res area add [领地] [区域ID] —— 为领地添加物理区域</p><p>/res area remove [领地] [区域ID] —— 移除领地的物理区域</p><p>/res area remove [领地] [区域ID] —— 替换领地的物理区域</p><p>【注】 可以与其他领地区域重叠。</p><p>/res setmain &lt;领地&gt; —— 设置主领地</p><h2 id="领地权限与名称" tabindex="-1">领地权限与名称 <a class="header-anchor" href="#领地权限与名称" aria-label="Permalink to &quot;领地权限与名称&quot;">​</a></h2><p>/res message &lt;领地名&gt; [enter/leave] [信息] —— 自定义玩家进入或离开领地的消息，</p><p>【注】（enter=进入,leave=离开）（信息可以是彩色&amp;的）</p><p>/res info —— 显示目前所处的领地信息，如果在领地外使用该指令，将会显示自己的领地信息</p><p>/res list [玩家] —— 列出玩家拥有的领地信息</p><p>/res listall &lt;页码&gt; —— 列出玩家所有领地</p><p>/res area list [领地] &lt;页码&gt; —— 列出领地的物理区域</p><p>/res area listall [领地] &lt;页码&gt; —— 列出所有区域的坐标和详细信息</p><p>/res lists —— 预定义的权限列表可以应用到领地上</p><p>/res lists add &lt;列表名&gt; —— 添加一个列表</p><p>/res lists remove &lt;列表名&gt; —— 删除一个列表</p><p>/res lists apply &lt;列表名&gt; &lt;领地&gt; —— 将列表应用于领地</p><p>/res lists set &lt;列表名&gt; &lt;权限&gt; &lt;值&gt; —— 设置列表全局权限</p><p>/res lists pset &lt;列表名&gt; &lt;玩家&gt; &lt;权限&gt; &lt;值&gt; —— 设置列表玩家权限</p><p>/res lists view &lt;列表名&gt; —— 设置列表组权限</p><p>/res lists view &lt;列表名&gt; —— 查看列表</p><p>/res listhidden &lt;玩家&gt; &lt;页码&gt; —— 列出指定玩家拥有的隐藏领地</p><h2 id="传送相关" tabindex="-1">传送相关 <a class="header-anchor" href="#传送相关" aria-label="Permalink to &quot;传送相关&quot;">​</a></h2><p>/res tp [领地名] —— 传送到指定领地</p><p>/res tpset —— 设置领地中的传送位置（当玩家输入/res tp [领地名]时，将会传送至您在领地内设置的传送位置）</p><p>/res unstuck —— 将您移动到你所在的领地外</p><p>领地使用 /res show &lt;领地&gt; —— 显示领地的边界</p><p>/res give [领地名] [玩家] —— 将所选领地给予给另外一名玩家！(该玩家须在线，且你是领地所有者。)</p><p>Pager</p>',49)]))}const m=t(a,[["render",l]]);export{g as __pageData,m as default};
